import React from 'react';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, AreaChart, Area } from 'recharts';
import { Transaction, TransactionType } from '../types';

interface DashboardProps {
  transactions: Transaction[];
}

const Dashboard: React.FC<DashboardProps> = ({ transactions }) => {
  const totalIncome = transactions
    .filter(t => t.type === TransactionType.INCOME)
    .reduce((sum, t) => sum + t.amount, 0);

  const totalExpense = transactions
    .filter(t => t.type === TransactionType.EXPENSE)
    .reduce((sum, t) => sum + t.amount, 0);

  const netProfit = totalIncome - totalExpense;

  // Aggregate monthly data
  const months = ['Jan', 'Fev', 'Mar', 'Abr', 'Mai', 'Jun', 'Jul', 'Ago', 'Set', 'Out', 'Nov', 'Dez'];
  const chartData = months.map((month, idx) => {
    const monthTransactions = transactions.filter(t => new Date(t.date).getMonth() === idx);
    const income = monthTransactions.filter(t => t.type === TransactionType.INCOME).reduce((s, t) => s + t.amount, 0);
    const expenses = monthTransactions.filter(t => t.type === TransactionType.EXPENSE).reduce((s, t) => s + t.amount, 0);
    return { month, income, expenses };
  });

  const StatCard = ({ title, value, type }: { title: string, value: string, type: 'plus' | 'minus' | 'neutral' }) => (
    <div className="bg-stone-900 border border-stone-800 p-6 rounded-2xl shadow-sm">
      <p className="text-sm text-stone-500 font-medium uppercase tracking-wider mb-2">{title}</p>
      <h3 className={`text-3xl font-bold ${
        type === 'plus' ? 'text-green-500' : type === 'minus' ? 'text-red-400' : 'text-amber-500'
      }`}>{value}</h3>
      <div className="mt-4 flex items-center text-xs text-stone-600">
        <span>Atualizado em tempo real</span>
      </div>
    </div>
  );

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        <StatCard title="Entrada Total" value={`R$ ${totalIncome.toLocaleString('pt-BR')}`} type="plus" />
        <StatCard title="Saída Total" value={`R$ ${totalExpense.toLocaleString('pt-BR')}`} type="minus" />
        <StatCard title="Lucro Líquido" value={`R$ ${netProfit.toLocaleString('pt-BR')}`} type="neutral" />
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        <div className="bg-stone-900 border border-stone-800 p-6 rounded-2xl">
          <h4 className="text-lg font-semibold mb-6 text-stone-200">Fluxo de Caixa Mensal</h4>
          <div className="h-80">
            <ResponsiveContainer width="100%" height="100%">
              <AreaChart data={chartData}>
                <defs>
                  <linearGradient id="colorIncome" x1="0" y1="0" x2="0" y2="1">
                    <stop offset="5%" stopColor="#10b981" stopOpacity={0.3}/>
                    <stop offset="95%" stopColor="#10b981" stopOpacity={0}/>
                  </linearGradient>
                  <linearGradient id="colorExpense" x1="0" y1="0" x2="0" y2="1">
                    <stop offset="5%" stopColor="#f87171" stopOpacity={0.3}/>
                    <stop offset="95%" stopColor="#f87171" stopOpacity={0}/>
                  </linearGradient>
                </defs>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#292524" />
                <XAxis dataKey="month" stroke="#78716c" fontSize={12} tickLine={false} axisLine={false} />
                <YAxis stroke="#78716c" fontSize={12} tickLine={false} axisLine={false} tickFormatter={(val) => `R$${val}`} />
                <Tooltip 
                  contentStyle={{ backgroundColor: '#1c1917', border: '1px solid #444', borderRadius: '8px' }}
                  itemStyle={{ color: '#fff' }}
                />
                <Area type="monotone" dataKey="income" stroke="#10b981" fillOpacity={1} fill="url(#colorIncome)" strokeWidth={2} />
                <Area type="monotone" dataKey="expenses" stroke="#f87171" fillOpacity={1} fill="url(#colorExpense)" strokeWidth={2} />
              </AreaChart>
            </ResponsiveContainer>
          </div>
        </div>

        <div className="bg-stone-900 border border-stone-800 p-6 rounded-2xl">
          <h4 className="text-lg font-semibold mb-6 text-stone-200">Desempenho por Categoria</h4>
          <div className="h-80">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={chartData}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#292524" />
                <XAxis dataKey="month" stroke="#78716c" fontSize={12} tickLine={false} axisLine={false} />
                <YAxis stroke="#78716c" fontSize={12} tickLine={false} axisLine={false} />
                <Tooltip 
                   contentStyle={{ backgroundColor: '#1c1917', border: '1px solid #444', borderRadius: '8px' }}
                />
                <Bar dataKey="income" fill="#d97706" radius={[4, 4, 0, 0]} />
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Dashboard;

import React, { useState } from 'react';
import { TransactionType, Collaborator } from '../types';
import { CATEGORIES } from '../constants';

interface TransactionFormProps {
  collaborators: Collaborator[];
  onAdd: (transaction: {
    description: string;
    amount: number;
    date: string;
    type: TransactionType;
    collaboratorId?: string;
    category: string;
  }) => void;
}

const TransactionForm: React.FC<TransactionFormProps> = ({ collaborators, onAdd }) => {
  const [type, setType] = useState<TransactionType>(TransactionType.INCOME);
  const [description, setDescription] = useState('');
  const [amount, setAmount] = useState('');
  const [date, setDate] = useState(new Date().toISOString().split('T')[0]);
  const [category, setCategory] = useState(CATEGORIES[0]);
  const [collaboratorId, setCollaboratorId] = useState('');

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!description || !amount) return;

    onAdd({
      description,
      amount: parseFloat(amount),
      date,
      type,
      category,
      collaboratorId: type === TransactionType.INCOME ? collaboratorId : undefined
    });

    setDescription('');
    setAmount('');
  };

  return (
    <div className="bg-stone-900 border border-stone-800 p-6 rounded-2xl mb-8">
      <h3 className="text-lg font-semibold text-stone-200 mb-6">Nova Entrada/Saída</h3>
      <form onSubmit={handleSubmit} className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        <div className="space-y-2">
          <label className="text-xs text-stone-500 uppercase tracking-widest font-bold">Tipo</label>
          <div className="flex p-1 bg-stone-950 rounded-lg border border-stone-800">
            <button
              type="button"
              onClick={() => setType(TransactionType.INCOME)}
              className={`flex-1 py-2 text-sm rounded-md transition-all ${type === TransactionType.INCOME ? 'bg-amber-600 text-white shadow-sm' : 'text-stone-500 hover:text-stone-300'}`}
            >
              Receita
            </button>
            <button
              type="button"
              onClick={() => setType(TransactionType.EXPENSE)}
              className={`flex-1 py-2 text-sm rounded-md transition-all ${type === TransactionType.EXPENSE ? 'bg-amber-600 text-white shadow-sm' : 'text-stone-500 hover:text-stone-300'}`}
            >
              Despesa
            </button>
          </div>
        </div>

        <div className="space-y-2">
          <label className="text-xs text-stone-500 uppercase tracking-widest font-bold">Descrição</label>
          <input
            type="text"
            value={description}
            onChange={(e) => setDescription(e.target.value)}
            placeholder="Ex: Corte Degrade"
            className="w-full bg-stone-950 border border-stone-800 rounded-lg px-4 py-2 text-stone-200 focus:outline-none focus:border-amber-600"
          />
        </div>

        <div className="space-y-2">
          <label className="text-xs text-stone-500 uppercase tracking-widest font-bold">Valor (R$)</label>
          <input
            type="number"
            value={amount}
            onChange={(e) => setAmount(e.target.value)}
            placeholder="0.00"
            className="w-full bg-stone-950 border border-stone-800 rounded-lg px-4 py-2 text-stone-200 focus:outline-none focus:border-amber-600"
          />
        </div>

        <div className="space-y-2">
          <label className="text-xs text-stone-500 uppercase tracking-widest font-bold">Data</label>
          <input
            type="date"
            value={date}
            onChange={(e) => setDate(e.target.value)}
            className="w-full bg-stone-950 border border-stone-800 rounded-lg px-4 py-2 text-stone-200 focus:outline-none focus:border-amber-600"
          />
        </div>

        <div className="space-y-2">
          <label className="text-xs text-stone-500 uppercase tracking-widest font-bold">Categoria</label>
          <select
            value={category}
            onChange={(e) => setCategory(e.target.value)}
            className="w-full bg-stone-950 border border-stone-800 rounded-lg px-4 py-2 text-stone-200 focus:outline-none focus:border-amber-600"
          >
            {CATEGORIES.map(cat => (
              <option key={cat} value={cat}>{cat}</option>
            ))}
          </select>
        </div>

        {type === TransactionType.INCOME && (
          <div className="space-y-2">
            <label className="text-xs text-stone-500 uppercase tracking-widest font-bold">Colaborador</label>
            <select
              value={collaboratorId}
              onChange={(e) => setCollaboratorId(e.target.value)}
              className="w-full bg-stone-950 border border-stone-800 rounded-lg px-4 py-2 text-stone-200 focus:outline-none focus:border-amber-600"
            >
              <option value="">Nenhum (Casa)</option>
              {collaborators.map(c => (
                <option key={c.id} value={c.id}>{c.name}</option>
              ))}
            </select>
          </div>
        )}

        <div className="md:col-span-2 lg:col-span-3 flex justify-end">
          <button
            type="submit"
            className="bg-stone-100 text-stone-950 hover:bg-white px-8 py-3 rounded-xl font-bold transition-all shadow-lg active:scale-95"
          >
            Lançar Registro
          </button>
        </div>
      </form>
    </div>
  );
};

export default TransactionForm;

import React, { useState, useEffect, useMemo } from 'react';
import { Transaction, Collaborator, TransactionType } from './types';
import { INITIAL_COLLABORATORS, MOCK_TRANSACTIONS } from './constants';
import Sidebar from './components/Sidebar';
import Dashboard from './components/Dashboard';
import TransactionForm from './components/TransactionForm';
import { getBusinessInsights } from './services/geminiService';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('dashboard');
  const [collaborators, setCollaborators] = useState<Collaborator[]>(INITIAL_COLLABORATORS);
  const [transactions, setTransactions] = useState<Transaction[]>(() => {
    const saved = localStorage.getItem('barber_transactions');
    return saved ? JSON.parse(saved) : MOCK_TRANSACTIONS;
  });
  const [aiInsights, setAiInsights] = useState<string>('');
  const [isLoadingAi, setIsLoadingAi] = useState(false);

  useEffect(() => {
    localStorage.setItem('barber_transactions', JSON.stringify(transactions));
  }, [transactions]);

  const addTransaction = (data: any) => {
    const newTx: Transaction = {
      id: Math.random().toString(36).substr(2, 9),
      ...data
    };
    setTransactions(prev => [newTx, ...prev]);
  };

  const loadAiInsights = async () => {
    setIsLoadingAi(true);
    const insights = await getBusinessInsights(transactions, collaborators);
    setAiInsights(insights || '');
    setIsLoadingAi(false);
  };

  const collaboratorCommissions = useMemo(() => {
    return collaborators.map(c => {
      const services = transactions.filter(t => t.collaboratorId === c.id && t.type === TransactionType.INCOME);
      const totalGenerated = services.reduce((sum, t) => sum + t.amount, 0);
      const commissionAmount = (totalGenerated * c.commission) / 100;
      return {
        ...c,
        totalGenerated,
        commissionAmount
      };
    });
  }, [transactions, collaborators]);

  const renderContent = () => {
    switch (activeTab) {
      case 'dashboard':
        return (
          <div className="space-y-8">
            <header className="flex justify-between items-center">
              <div>
                <h2 className="text-3xl font-serif text-stone-100">Visão Geral</h2>
                <p className="text-stone-500">Acompanhe a saúde financeira da sua barbearia</p>
              </div>
              <button 
                onClick={loadAiInsights}
                disabled={isLoadingAi}
                className="bg-amber-600/10 text-amber-500 border border-amber-500/30 px-4 py-2 rounded-xl text-sm font-semibold hover:bg-amber-600 hover:text-white transition-all flex items-center space-x-2"
              >
                <span>✨ IA Consultor</span>
                {isLoadingAi && <div className="animate-spin h-4 w-4 border-2 border-white border-t-transparent rounded-full"></div>}
              </button>
            </header>

            {aiInsights && (
              <div className="bg-amber-900/10 border border-amber-900/30 p-6 rounded-2xl relative overflow-hidden">
                <div className="absolute top-0 right-0 p-4 text-amber-600 opacity-20 text-6xl font-serif">"</div>
                <h4 className="text-amber-500 font-bold mb-2 flex items-center space-x-2">
                  <span>Insight da Barber Intelligence</span>
                </h4>
                <div className="text-stone-300 text-sm leading-relaxed whitespace-pre-line">
                  {aiInsights}
                </div>
              </div>
            )}

            <Dashboard transactions={transactions} />
          </div>
        );

      case 'transactions':
        return (
          <div className="space-y-8">
            <div>
              <h2 className="text-3xl font-serif text-stone-100">Gestão de Transações</h2>
              <p className="text-stone-500">Registre novos serviços e despesas da unidade</p>
            </div>

            <TransactionForm collaborators={collaborators} onAdd={addTransaction} />

            <div className="bg-stone-900 border border-stone-800 rounded-2xl overflow-hidden">
              <div className="overflow-x-auto">
                <table className="w-full text-left">
                  <thead className="bg-stone-800/50 border-b border-stone-800">
                    <tr>
                      <th className="px-6 py-4 text-xs font-bold text-stone-500 uppercase tracking-widest">Data</th>
                      <th className="px-6 py-4 text-xs font-bold text-stone-500 uppercase tracking-widest">Descrição</th>
                      <th className="px-6 py-4 text-xs font-bold text-stone-500 uppercase tracking-widest">Categoria</th>
                      <th className="px-6 py-4 text-xs font-bold text-stone-500 uppercase tracking-widest">Colaborador</th>
                      <th className="px-6 py-4 text-xs font-bold text-stone-500 uppercase tracking-widest text-right">Valor</th>
                    </tr>
                  </thead>
                  <tbody className="divide-y divide-stone-800">
                    {transactions.map((t) => (
                      <tr key={t.id} className="hover:bg-stone-800/30 transition-colors">
                        <td className="px-6 py-4 text-sm text-stone-400">{new Date(t.date).toLocaleDateString('pt-BR')}</td>
                        <td className="px-6 py-4 font-medium text-stone-200">{t.description}</td>
                        <td className="px-6 py-4">
                          <span className="bg-stone-800 text-stone-400 px-2 py-1 rounded text-[10px] font-bold uppercase tracking-wider">
                            {t.category}
                          </span>
                        </td>
                        <td className="px-6 py-4 text-sm text-stone-400">
                          {collaborators.find(c => c.id === t.collaboratorId)?.name || 'CASA'}
                        </td>
                        <td className={`px-6 py-4 text-right font-bold ${t.type === TransactionType.INCOME ? 'text-green-500' : 'text-red-400'}`}>
                          {t.type === TransactionType.INCOME ? '+' : '-'} R$ {t.amount.toFixed(2)}
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            </div>
          </div>
        );

      case 'collaborators':
        return (
          <div className="space-y-8">
            <div>
              <h2 className="text-3xl font-serif text-stone-100">Equipe & Comissões</h2>
              <p className="text-stone-500">Gestão de desempenho e pagamentos por colaborador</p>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
              {collaboratorCommissions.map(c => (
                <div key={c.id} className="bg-stone-900 border border-stone-800 p-6 rounded-2xl relative overflow-hidden group">
                  <div className="absolute -right-4 -top-4 w-24 h-24 bg-amber-600/5 rounded-full group-hover:bg-amber-600/10 transition-all"></div>
                  <div className="flex items-center space-x-4 mb-6">
                    <div className="w-12 h-12 bg-stone-800 rounded-xl flex items-center justify-center text-2xl">
                      🧔
                    </div>
                    <div>
                      <h4 className="font-bold text-stone-100">{c.name}</h4>
                      <p className="text-xs text-stone-500 uppercase tracking-widest">{c.role}</p>
                    </div>
                  </div>

                  <div className="space-y-4">
                    <div className="flex justify-between items-end">
                      <p className="text-xs text-stone-500 uppercase font-bold tracking-widest">Comissão Fixa</p>
                      <p className="text-amber-500 font-bold">{c.commission}%</p>
                    </div>
                    <div className="h-px bg-stone-800"></div>
                    <div className="flex justify-between items-end">
                      <div>
                        <p className="text-xs text-stone-500 uppercase font-bold tracking-widest">Total Gerado</p>
                        <p className="text-xl font-bold text-stone-100">R$ {c.totalGenerated.toFixed(2)}</p>
                      </div>
                      <div className="text-right">
                        <p className="text-xs text-stone-500 uppercase font-bold tracking-widest">A Pagar</p>
                        <p className="text-xl font-bold text-green-500">R$ {c.commissionAmount.toFixed(2)}</p>
                      </div>
