import TransactionForm from './components/TransactionForm';
import { getBusinessInsights } from './services/geminiService';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('dashboard');
  const [collaborators, setCollaborators] = useState<Collaborator[]>(INITIAL_COLLABORATORS);
  const [transactions, setTransactions] = useState<Transaction[]>(() => {
    const saved = localStorage.getItem('barber_transactions');
    return saved ? JSON.parse(saved) : MOCK_TRANSACTIONS;
  });
  const [aiInsights, setAiInsights] = useState<string>('');
  const [isLoadingAi, setIsLoadingAi] = useState(false);

  useEffect(() => {
    localStorage.setItem('barber_transactions', JSON.stringify(transactions));
  }, [transactions]);

  const addTransaction = (data: any) => {
    const newTx: Transaction = {
      id: Math.random().toString(36).substr(2, 9),
      ...data
    };
    setTransactions(prev => [newTx, ...prev]);
  };

  const loadAiInsights = async () => {
    setIsLoadingAi(true);
    const insights = await getBusinessInsights(transactions, collaborators);
    setAiInsights(insights || '');
    setIsLoadingAi(false);
  };

  const collaboratorCommissions = useMemo(() => {
    return collaborators.map(c => {
      const services = transactions.filter(t => t.collaboratorId === c.id && t.type === TransactionType.INCOME);
      const totalGenerated = services.reduce((sum, t) => sum + t.amount, 0);
      const commissionAmount = (totalGenerated * c.commission) / 100;
      return {
        ...c,
        totalGenerated,
        commissionAmount
      };
    }).sort((a, b) => b.totalGenerated - a.totalGenerated);
