                    </div>
                  </div>
                </div>
              ))}
            </div>
          </div>
        );

      case 'closing':
        return (
          <div className="space-y-8">
            <div>
              <h2 className="text-3xl font-serif text-stone-100">Fechamento do Exercício</h2>
              <p className="text-stone-500">Análise crítica de lucros e perdas do ano</p>
            </div>
            <div className="bg-stone-900 border border-stone-800 p-10 rounded-3xl text-center">
              <div className="max-w-md mx-auto space-y-6">
                <div className="text-6xl mb-4">📈</div>
                <h3 className="text-2xl font-bold">Pronto para o Próximo Ano?</h3>
                <p className="text-stone-400">O sistema calculou que sua margem média foi de {(( (transactions.filter(t => t.type === TransactionType.INCOME).reduce((s,t)=>s+t.amount,0) - transactions.filter(t => t.type === TransactionType.EXPENSE).reduce((s,t)=>s+t.amount,0)) / transactions.filter(t => t.type === TransactionType.INCOME).reduce((s,t)=>s+t.amount,0)) * 100).toFixed(1)}%.</p>
