import Dashboard from './components/Dashboard';
import TransactionForm from './components/TransactionForm';
import { getBusinessInsights } from './services/geminiService';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('dashboard');
  const [collaborators, setCollaborators] = useState<Collaborator[]>(INITIAL_COLLABORATORS);
  const [transactions, setTransactions] = useState<Transaction[]>(() => {
    const saved = localStorage.getItem('barber_transactions');
    return saved ? JSON.parse(saved) : MOCK_TRANSACTIONS;
  });
  const [aiInsights, setAiInsights] = useState<string>('');
  const [isLoadingAi, setIsLoadingAi] = useState(false);

  useEffect(() => {
    localStorage.setItem('barber_transactions', JSON.stringify(transactions));
  }, [transactions]);

  const addTransaction = (data: any) => {
    const newTx: Transaction = {
      id: Math.random().toString(36).substr(2, 9),
      ...data
    };
    setTransactions(prev => [newTx, ...prev]);
  };

  const months = ['Jan', 'Fev', 'Mar', 'Abr', 'Mai', 'Jun', 'Jul', 'Ago', 'Set', 'Out', 'Nov', 'Dez'];

  const monthlyMatrix = useMemo(() => {
    return months.map((m, idx) => {
      const monthTxs = transactions.filter(t => new Date(t.date).getMonth() === idx);
      return {
        month: m,
        servicos: monthTxs.filter(t => t.category.includes('Serviços')).reduce((s,t) => s + t.amount, 0),
        assinaturas: monthTxs.filter(t => t.category.includes('Assinaturas')).reduce((s,t) => s + t.amount, 0),
        produtos: monthTxs.filter(t => t.category.includes('Produtos')).reduce((s,t) => s + t.amount, 0),
        comissoes: monthTxs.filter(t => t.category.includes('Comissões')).reduce((s,t) => s + t.amount, 0),
        totalIncome: monthTxs.filter(t => t.type === TransactionType.INCOME).reduce((s,t) => s + t.amount, 0),
        totalExpense: monthTxs.filter(t => t.type === TransactionType.EXPENSE).reduce((s,t) => s + t.amount, 0),
      };
    });
  }, [transactions]);

  const renderContent = () => {
    switch (activeTab) {
      case 'dashboard':
        return (
          <div className="space-y-8">
            <header className="flex justify-between items-center">
              <div>
                <h2 className="text-3xl font-serif text-stone-100">Painel de Controle</h2>
                <p className="text-stone-500 text-sm">Visão geral do desempenho financeiro anual</p>
              </div>
              <button 
                onClick={async () => {
                  setIsLoadingAi(true);
                  const res = await getBusinessInsights(transactions, collaborators);
                  setAiInsights(res);
                  setIsLoadingAi(false);
                }}
                disabled={isLoadingAi}
                className="bg-amber-600/10 text-amber-500 border border-amber-500/30 px-4 py-2 rounded-xl text-sm font-semibold hover:bg-amber-600 hover:text-white transition-all flex items-center gap-2"
              >
                <span>✨ IA Consultor</span>
                {isLoadingAi && <div className="animate-spin h-3 w-3 border-2 border-white border-t-transparent rounded-full"></div>}
              </button>
            </header>

            {aiInsights && (
              <div className="bg-stone-900 border-l-4 border-amber-600 p-6 rounded-r-2xl">
                <p className="text-xs font-bold text-amber-600 uppercase tracking-widest mb-2">Análise Estratégica</p>
                <div className="text-stone-300 text-sm leading-relaxed whitespace-pre-line">{aiInsights}</div>
              </div>
            )}

            <Dashboard transactions={transactions} collaborators={collaborators} />
          </div>
        );

      case 'transactions':
        return (
          <div className="space-y-8">
            <h2 className="text-3xl font-serif text-stone-100">Lançamento Consolidado</h2>
            <TransactionForm collaborators={collaborators} onAdd={addTransaction} />
            <div className="bg-stone-900 border border-stone-800 rounded-2xl overflow-hidden">
               <table className="w-full text-left text-sm">
                <thead className="bg-stone-800/50 text-stone-500 font-bold uppercase text-[10px] tracking-widest">
                  <tr>
                    <th className="px-6 py-4">Data</th>
                    <th className="px-6 py-4">Categoria</th>
                    <th className="px-6 py-4">Descrição</th>
                    <th className="px-6 py-4 text-right">Valor</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-stone-800">
                  {transactions.slice(0, 15).map(t => (
                    <tr key={t.id} className="hover:bg-stone-800/20">
                      <td className="px-6 py-4 text-stone-400">{new Date(t.date).toLocaleDateString('pt-BR')}</td>
                      <td className="px-6 py-4 font-medium text-stone-200">{t.category}</td>
                      <td className="px-6 py-4 text-stone-500">{t.description}</td>
                      <td className={`px-6 py-4 text-right font-bold ${t.type === TransactionType.INCOME ? 'text-green-500' : 'text-red-400'}`}>
                        R$ {t.amount.toLocaleString('pt-BR')}
                      </td>
                    </tr>
                  ))}
                </tbody>
               </table>
            </div>
          </div>
        );

      case 'closing':
        return (
          <div className="space-y-8">
             <header>
                <h2 className="text-3xl font-serif text-stone-100">Fechamento Mês a Mês</h2>
                <p className="text-stone-500 text-sm">Consolidado anual no estilo planilha</p>
              </header>

              <div className="bg-stone-900 border border-stone-800 rounded-3xl overflow-hidden shadow-2xl">
                <div className="overflow-x-auto">
                  <table className="w-full text-left border-collapse">
                    <thead className="bg-stone-950 border-b border-stone-800 text-[10px] font-bold uppercase text-stone-500 tracking-tighter">
                      <tr>
                        <th className="px-4 py-5 sticky left-0 bg-stone-950">Mês</th>
                        <th className="px-4 py-5">Serviços</th>
                        <th className="px-4 py-5">Assinaturas</th>
                        <th className="px-4 py-5">Produtos</th>
                        <th className="px-4 py-5">Comissões (S)</th>
                        <th className="px-4 py-5">Rec. Bruta</th>
                        <th className="px-4 py-5">Saldo Líq.</th>
                      </tr>
                    </thead>
                    <tbody className="divide-y divide-stone-800 text-sm">
                      {monthlyMatrix.map((m) => (
                        <tr key={m.month} className="hover:bg-amber-600/5 transition-colors">
                          <td className="px-4 py-4 font-bold text-stone-100 sticky left-0 bg-stone-900 border-r border-stone-800">{m.month}</td>
                          <td className="px-4 py-4 text-stone-400">R$ {m.servicos.toLocaleString('pt-BR')}</td>
                          <td className="px-4 py-4 text-blue-400">R$ {m.assinaturas.toLocaleString('pt-BR')}</td>
                          <td className="px-4 py-4 text-stone-400">R$ {m.produtos.toLocaleString('pt-BR')}</td>
                          <td className="px-4 py-4 text-red-400">R$ {m.comissoes.toLocaleString('pt-BR')}</td>
                          <td className="px-4 py-4 font-bold text-green-500">R$ {m.totalIncome.toLocaleString('pt-BR')}</td>
                          <td className={`px-4 py-4 font-bold ${m.totalIncome - m.totalExpense >= 0 ? 'text-stone-100' : 'text-red-500'}`}>
                            R$ {(m.totalIncome - m.totalExpense).toLocaleString('pt-BR')}
                          </td>
                        </tr>
                      ))}
                    </tbody>
                    <tfoot className="bg-stone-950 font-bold border-t-2 border-amber-600">
                      <tr>
                        <td className="px-4 py-6 sticky left-0 bg-stone-950 uppercase text-[10px]">Total Anual</td>
                        <td className="px-4 py-6">R$ {monthlyMatrix.reduce((s,m)=>s+m.servicos,0).toLocaleString('pt-BR')}</td>
                        <td className="px-4 py-6">R$ {monthlyMatrix.reduce((s,m)=>s+m.assinaturas,0).toLocaleString('pt-BR')}</td>
                        <td className="px-4 py-6">R$ {monthlyMatrix.reduce((s,m)=>s+m.produtos,0).toLocaleString('pt-BR')}</td>
                        <td className="px-4 py-6">R$ {monthlyMatrix.reduce((s,m)=>s+m.comissoes,0).toLocaleString('pt-BR')}</td>
                        <td className="px-4 py-6 text-green-500 text-lg">R$ {monthlyMatrix.reduce((s,m)=>s+m.totalIncome,0).toLocaleString('pt-BR')}</td>
                        <td className="px-4 py-6 text-lg">R$ {(monthlyMatrix.reduce((s,m)=>s+m.totalIncome,0) - monthlyMatrix.reduce((s,m)=>s+m.totalExpense,0)).toLocaleString('pt-BR')}</td>
                      </tr>
                    </tfoot>
                  </table>
                </div>
              </div>

              <div className="bg-amber-600/10 border border-amber-600/20 p-8 rounded-3xl text-center">
                <h3 className="text-xl font-bold text-amber-500 mb-2">🏅 Profissional do Ano</h3>
                <p className="text-stone-400 text-sm mb-6">Baseado no volume total de serviços gerados para a barbearia.</p>
                <div className="flex justify-center">
                  <div className="bg-stone-900 border border-stone-800 p-6 rounded-2xl w-full max-w-sm">
                    <span className="text-4xl block mb-2">🥇</span>
                    <p className="text-2xl font-serif text-white">João Tesoura</p>
                    <p className="text-xs text-stone-500 uppercase tracking-widest mt-1">Barbeiro Master</p>
                  </div>
                </div>
              </div>
          </div>
        );

      case 'collaborators':
        return (
          <div className="space-y-8">
            <h2 className="text-3xl font-serif text-stone-100">Equipe & Comissões</h2>
             <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
              {collaborators.map(c => {
                const totalIncome = transactions.filter(t => t.collaboratorId === c.id && t.type === TransactionType.INCOME).reduce((s,t)=>s+t.amount,0);
                const comissionsPaid = transactions.filter(t => t.collaboratorId === c.id && t.type === TransactionType.EXPENSE && t.category.includes('Comissões')).reduce((s,t)=>s+t.amount,0);
                return (
                  <div key={c.id} className="bg-stone-900 border border-stone-800 p-6 rounded-2xl">
                    <div className="flex justify-between items-start mb-4">
                      <div className="w-10 h-10 bg-amber-600/20 rounded-lg flex items-center justify-center text-amber-500 font-bold">
                        {c.name.charAt(0)}
                      </div>
                      <span className="text-[10px] bg-stone-800 text-stone-400 px-2 py-1 rounded font-bold">{c.role}</span>
                    </div>
                    <h4 className="font-bold text-lg mb-4">{c.name}</h4>
                    <div className="space-y-3 border-t border-stone-800 pt-4">
                      <div className="flex justify-between text-sm">
                        <span className="text-stone-500">Prod. Anual</span>
                        <span className="text-stone-200 font-bold">R$ {totalIncome.toLocaleString('pt-BR')}</span>
                      </div>
                      <div className="flex justify-between text-sm">
                        <span className="text-stone-500">Comissões Pagas</span>
                        <span className="text-red-400 font-bold">R$ {comissionsPaid.toLocaleString('pt-BR')}</span>
                      </div>
                    </div>
                  </div>
                );
              })}
             </div>
          </div>
        );

      default:
        return <div>Selecione uma aba</div>;
    }
  };

  return (
    <div className="min-h-screen flex bg-stone-950">
      <Sidebar activeTab={activeTab} setActiveTab={setActiveTab} />
      <main className="flex-1 ml-64 p-10 max-w-7xl mx-auto w-full">
        {renderContent()}
      </main>
    </div>
  );
};

export default App;
